import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as t,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation এবং Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Safety/image-moderation-and-access-mode.md","filePath":"bn-BD/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"bn-BD/Safety/image-moderation-and-access-mode.md"};function o(n,e,s,c,m,u){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="image-moderation-এবং-access-mode" tabindex="-1">Image Moderation এবং Access Mode <a class="header-anchor" href="#image-moderation-এবং-access-mode" aria-label="Permalink to &quot;Image Moderation এবং Access Mode&quot;">​</a></h1><p>Image moderation uploaded images-কে age rating দেয়। Access mode ঠিক করে public access-এ কোন ratings দেখা যাবে।</p><p>এটি public gallery, public file URLs এবং random image API-তে প্রভাব ফেলে। Admin panel restrict করে না। Administrators এখনও সব files দেখতে এবং manage করতে পারবেন।</p><h2 id="কোথায়-configure-করবেন" tabindex="-1">কোথায় Configure করবেন <a class="header-anchor" href="#কোথায়-configure-করবেন" aria-label="Permalink to &quot;কোথায় Configure করবেন&quot;">​</a></h2><p>Admin panel খুলে যান:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>প্রধান settings:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-কী-করে" tabindex="-1">Access Mode কী করে <a class="header-anchor" href="#access-mode-কী-করে" aria-label="Permalink to &quot;Access Mode কী করে&quot;">​</a></h2><p>Access mode publicভাবে কোন age ratings দেখা যাবে তা ঠিক করে।</p><p>Current modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>শুধু General</td></tr></tbody></table><p>Default হলো Adult mode।</p><p>Private sites বা mature content থাকা sites-এর জন্য Adult mode ঠিক হতে পারে। Public gallery বেশি conservative রাখতে চাইলে Youth, Teen বা Child mode বেছে নিন।</p><h2 id="moderation-enable-করলে-কী-হয়" tabindex="-1">Moderation Enable করলে কী হয় <a class="header-anchor" href="#moderation-enable-করলে-কী-হয়" aria-label="Permalink to &quot;Moderation Enable করলে কী হয়&quot;">​</a></h2><p>Moderation enabled থাকলে ImgBed upload-এর সময় selected moderation provider call করে এবং detected age rating save করে।</p><p>প্রধান ratings:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>Safe public content</td></tr><tr><td>R12</td><td>হালকা sensitive content</td></tr><tr><td>R16</td><td>মাঝারি sensitive content</td></tr><tr><td>R18</td><td>Adult content</td></tr></tbody></table><p>Public access সিদ্ধান্ত নিতে moderation result ব্যবহার হয়।</p><p>Moderation enabled না থাকলে, বা পুরোনো files-এর rating না থাকলে, সেগুলো unrated হিসেবে ধরা হয়। শুধু rating নেই বলে unrated files public gallery বা random image API থেকে automatically সরানো হয় না।</p><h2 id="moderation-provider-নির্বাচন" tabindex="-1">Moderation Provider নির্বাচন <a class="header-anchor" href="#moderation-provider-নির্বাচন" aria-label="Permalink to &quot;Moderation Provider নির্বাচন&quot;">​</a></h2><p>Available providers:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>প্রতিটি provider-এর requirements আলাদা:</p><ul><li>moderatecontent.com সাধারণত API Key চায়।</li><li>nsfwjs সাধারণত API endpoint URL চায়।</li><li>Sightengine API user এবং API secret চায়।</li></ul><p>আপনার account, availability এবং detection quality অনুযায়ী provider বেছে নিন। Moderation enabled এবং ঠিকভাবে configured থাকলে ImgBed upload-এর সময় image rating লিখতে চেষ্টা করে।</p><h2 id="public-gallery-তে-প্রভাব" tabindex="-1">Public Gallery-তে প্রভাব <a class="header-anchor" href="#public-gallery-তে-প্রভাব" aria-label="Permalink to &quot;Public Gallery-তে প্রভাব&quot;">​</a></h2><p>Public gallery access mode অনুযায়ী files filter করে।</p><p>Examples:</p><ul><li>Adult mode: R18 images দেখা যেতে পারে।</li><li>Youth mode: R18 images hidden হয়।</li><li>Teen mode: R16 এবং R18 images hidden হয়।</li><li>Child mode: শুধু General images দেখায়।</li></ul><p>এটি শুধু normal public access-এ প্রভাব ফেলে। Admin panel সব files দেখাবে।</p><h2 id="public-file-urls-এ-প্রভাব" tabindex="-1">Public File URLs-এ প্রভাব <a class="header-anchor" href="#public-file-urls-এ-প্রভাব" aria-label="Permalink to &quot;Public File URLs-এ প্রভাব&quot;">​</a></h2><p>Public file URLs হলো visitors যে direct image links খোলে।</p><p>File rating current access mode-এ allowed হলে ImgBed original image return করে।</p><p>Rating allowed level-এর বেশি হলে normal public access original image return করে না। এর বদলে ImgBed configured blocked result বা blocked fallback image return করে।</p><p>Example:</p><ul><li>Current mode হলো Child mode।</li><li>একটি image rating R18।</li><li>Visitor public URL সরাসরি খুলেছে।</li><li>ImgBed সেই visitor-কে R18 original image return করে না।</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>Admin panel-এ files দেখা administrators এই restriction-এ প্রভাবিত হন না।</p><h2 id="random-image-api-তে-প্রভাব" tabindex="-1">Random Image API-তে প্রভাব <a class="header-anchor" href="#random-image-api-তে-প্রভাব" aria-label="Permalink to &quot;Random Image API-তে প্রভাব&quot;">​</a></h2><p>Random image API-ও access mode অনুযায়ী candidate pool filter করে।</p><p>Child mode-এ random images শুধু General-rated files থেকে নেওয়া হয়।</p><p>Youth mode-এ random images General, R12 এবং R16 files থেকে আসতে পারে, কিন্তু R18 files থেকে নয়।</p><p>এতে random image API public gallery restrictions bypass করতে পারে না।</p><h2 id="list-rules-এর-সঙ্গে-সম্পর্ক" tabindex="-1">List Rules-এর সঙ্গে সম্পর্ক <a class="header-anchor" href="#list-rules-এর-সঙ্গে-সম্পর্ক" aria-label="Permalink to &quot;List Rules-এর সঙ্গে সম্পর্ক&quot;">​</a></h2><p>Access mode একমাত্র public access rule নয়। এটি allow/block list rules-এর সঙ্গে মিলিয়ে কাজ করে।</p><p>সহজভাবে:</p><ul><li>Allowlisted content আগে public ধরা হয়।</li><li>Blocklisted content regular visitors সরাসরি দেখতে পারে না।</li><li>যে content কোনো list-এ নেই, সেটি access mode অনুযায়ী check হয়।</li></ul><p>কোনো image age rating এবং list rules দুইভাবেই restricted হলে regular visitors original file সরাসরি দেখতে পারবে না।</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>Public sites-এর জন্য:</p><ul><li>Moderation enable করুন।</li><li>Site audience অনুযায়ী access mode নির্বাচন করুন।</li><li>All-age visitors-এর জন্য Child mode বা Teen mode ব্যবহার করুন।</li><li>Mature content publicly দেখাতে না চাইলে Adult mode এড়িয়ে চলুন।</li><li>Admin panel-এ file ratings review করে দরকার হলে manually adjust করুন।</li></ul><p>Private বা personal sites-এর জন্য:</p><ul><li>Adult mode সাধারণত ঠিক থাকে।</li><li>দরকার হলে moderation enable করুন।</li><li>Admin panel-এ ratings review এবং adjust করুন।</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="access-mode-বদলালে-files-কি-admin-panel-থেকে-হারিয়ে-যাবে" tabindex="-1">Access Mode বদলালে Files কি Admin Panel থেকে হারিয়ে যাবে? <a class="header-anchor" href="#access-mode-বদলালে-files-কি-admin-panel-থেকে-হারিয়ে-যাবে" aria-label="Permalink to &quot;Access Mode বদলালে Files কি Admin Panel থেকে হারিয়ে যাবে?&quot;">​</a></h3><p>না।</p><p>Access mode শুধু normal public access-এ প্রভাব ফেলে। Admin panel-এ এর প্রভাব নেই।</p><h3 id="child-mode-এ-যাওয়ার-পর-public-gallery-কম-images-দেখাচ্ছে-কেন" tabindex="-1">Child Mode-এ যাওয়ার পর Public Gallery কম Images দেখাচ্ছে কেন? <a class="header-anchor" href="#child-mode-এ-যাওয়ার-পর-public-gallery-কম-images-দেখাচ্ছে-কেন" aria-label="Permalink to &quot;Child Mode-এ যাওয়ার পর Public Gallery কম Images দেখাচ্ছে কেন?&quot;">​</a></h3><p>Child mode শুধু General-rated files publicly দেখায়। R12, R16 এবং R18 files filter হয়ে যায়।</p><h3 id="public-urls-কি-এখনও-adult-images-খুলতে-পারে" tabindex="-1">Public URLs কি এখনও Adult Images খুলতে পারে? <a class="header-anchor" href="#public-urls-কি-এখনও-adult-images-খুলতে-পারে" aria-label="Permalink to &quot;Public URLs কি এখনও Adult Images খুলতে পারে?&quot;">​</a></h3><p>Current access mode যদি সেই rating allow না করে, normal public URLs original image return করে না।</p><h3 id="random-image-api-কি-restricted-images-return-করতে-পারে" tabindex="-1">Random Image API কি Restricted Images return করতে পারে? <a class="header-anchor" href="#random-image-api-কি-restricted-images-return-করতে-পারে" aria-label="Permalink to &quot;Random Image API কি Restricted Images return করতে পারে?&quot;">​</a></h3><p>না।</p><p>Random image API current access mode অনুযায়ী candidates filter করে।</p><h3 id="পুরোনো-unrated-images-এর-কী-হবে" tabindex="-1">পুরোনো Unrated Images-এর কী হবে? <a class="header-anchor" href="#পুরোনো-unrated-images-এর-কী-হবে" aria-label="Permalink to &quot;পুরোনো Unrated Images-এর কী হবে?&quot;">​</a></h3><p>Unrated images শুধু moderation result নেই বলে automatically hidden হয় না। পরে admin panel থেকে ratings adjust করতে পারেন।</p>',67)])])}const b=i(d,[["render",o]]);export{h as __pageData,b as default};
